sql:
SELECT total_customers
FROM marketplace_metrics
WHERE customer_retention_rate > 0.75;

SELECT COUNT(*) AS number_of_marketplaces
FROM marketplace_metrics
WHERE customer_retention_rate > 0.6;

SELECT COUNT(DISTINCT product_id) AS unique_products_sold
FROM product_sales
WHERE marketplace_id = 0;

